import React, { useState, useEffect, useRef } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';
import './SearchBar.css';

const SearchBar = () => {
  const [searchTerm, setSearchTerm] = useState('');
  const [searchResults, setSearchResults] = useState({ articles: [], users: [] });
  const [showResults, setShowResults] = useState(false);
  const [loading, setLoading] = useState(false);
  const searchRef = useRef(null);
  const navigate = useNavigate();

  useEffect(() => {
    // Close results when clicking outside
    const handleClickOutside = (event) => {
      if (searchRef.current && !searchRef.current.contains(event.target)) {
        setShowResults(false);
      }
    };

    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  useEffect(() => {
    const delayDebounce = setTimeout(() => {
      if (searchTerm.trim()) {
        performSearch();
      } else {
        setSearchResults({ articles: [], users: [] });
        setShowResults(false);
      }
    }, 300);

    return () => clearTimeout(delayDebounce);
  }, [searchTerm]);

  const performSearch = async () => {
    setLoading(true);
    try {
      const token = localStorage.getItem('token');
      const headers = token ? { Authorization: `Bearer ${token}` } : {};

      const response = await axios.get(`http://localhost:3003/api/search?q=${searchTerm}`, { headers });
      setSearchResults(response.data);
      setShowResults(true);
    } catch (error) {
      console.error('Search error:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleResultClick = (type, id) => {
    setShowResults(false);
    setSearchTerm('');
    if (type === 'article') {
      navigate(`/article/${id}`);
    } else {
      navigate(`/profile/${id}`);
    }
  };

  return (
    <div className="search-bar-container" ref={searchRef}>
      <div className="search-input-wrapper">
        <span className="search-icon">🔍</span>
        <input
          type="text"
          placeholder="Search Medium..."
          value={searchTerm}
          onChange={(e) => setSearchTerm(e.target.value)}
          onFocus={() => searchTerm.trim() && setShowResults(true)}
          className="search-input"
        />
        {loading && <span className="search-loading">...</span>}
      </div>

      {showResults && (searchResults.articles?.length > 0 || searchResults.users?.length > 0) && (
        <div className="search-results">
          {searchResults.articles?.length > 0 && (
            <div className="search-section">
              <h4 className="search-section-title">Stories</h4>
              {searchResults.articles.map(article => (
                <div
                  key={article.id}
                  className="search-result-item"
                  onClick={() => handleResultClick('article', article.id)}
                >
                  <div className="result-icon">📄</div>
                  <div className="result-content">
                    <div className="result-title">{article.title}</div>
                    <div className="result-meta">
                      by {article.author_full_name} · {article.read_time} min read
                    </div>
                  </div>
                </div>
              ))}
            </div>
          )}

          {searchResults.users?.length > 0 && (
            <div className="search-section">
              <h4 className="search-section-title">People</h4>
              {searchResults.users.map(user => (
                <div
                  key={user.id}
                  className="search-result-item"
                  onClick={() => handleResultClick('user', user.id)}
                >
                  <div className="result-avatar">
                    {user.avatar_url ? (
                      <img src={user.avatar_url} alt={user.full_name} />
                    ) : (
                      <div className="avatar-placeholder-small">
                        {user.full_name?.charAt(0) || 'U'}
                      </div>
                    )}
                  </div>
                  <div className="result-content">
                    <div className="result-title">{user.full_name}</div>
                    <div className="result-meta">@{user.username}</div>
                    {user.bio && <div className="result-bio">{user.bio}</div>}
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      )}
    </div>
  );
};

export default SearchBar;
